{"path": "/tmp/sv-8dc960ca3f194efbb1b74d53508482fb/Components/Pages/Catalog/CatalogPagination.razor", "file_text": "@if (TotalPages > 1)
{
    <nav class="catalog-pagination" aria-label="Product pagination">
        <button class="page-btn"
                disabled="@(CurrentPage <= 1)"
                @onclick="@(() => GoToPage(CurrentPage - 1))">
            Previous
        </button>

        @foreach (var page in GetPageNumbers())
        {
            <button class="page-btn @(page == CurrentPage ? "active" : "")"
                    @onclick="@(() => GoToPage(page))">
                @page
            </button>
        }

        <button class="page-btn"
                disabled="@(CurrentPage >= TotalPages)"
                @onclick="@(() => GoToPage(CurrentPage + 1))">
            Next
        </button>
    </nav>
}

@code {
    [Parameter]
    public int CurrentPage { get; set; }

    [Parameter]
    public int TotalPages { get; set; }

    [Parameter]
    public EventCallback<int> OnPageChanged { get; set; }

    private async Task GoToPage(int page)
    {
        if (page >= 1 && page <= TotalPages && page != CurrentPage)
        {
            await OnPageChanged.InvokeAsync(page);
        }
    }

    private IEnumerable<int> GetPageNumbers()
    {
        const int maxVisible = 7;
        if (TotalPages <= maxVisible)
            return Enumerable.Range(1, TotalPages);

        var pages = new List<int>();
        int start = Math.Max(1, CurrentPage - 3);
        int end = Math.Min(TotalPages, start + maxVisible - 1);
        if (end - start < maxVisible - 1)
            start = Math.Max(1, end - maxVisible + 1);

        for (int i = start; i <= end; i++)
            pages.Add(i);

        return pages;
    }
}
"}

