@page "/catalog"
@using sv_8dc960ca3f194efbb1b74d53508482fb.Components.Pages.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h1>Product Catalog</h1>

@if (_error is not null)
{
    <div class="error-banner">
        <p>Something went wrong: @_error</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_loading)
{
    <div class="loading-state">
        <p>Loading products…</p>
    </div>
}
else
{
    <div class="catalog-layout">
        <div class="catalog-sidebar">
            <CatalogFilters Categories="_categories"
                            CurrentFilter="_filter"
                            OnFilterApplied="HandleFilterApplied"
                            OnFilterCleared="HandleFilterCleared" />
        </div>
        <div class="catalog-main">
            <CatalogToolbar SortBy="@_sortBy"
                            Page="_currentPage"
                            PageSize="PageSize"
                            TotalCount="_result?.TotalCount ?? 0"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="_result?.Items ?? []"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination CurrentPage="_currentPage"
                               TotalPages="_totalPages"
                               OnPageChanged="HandlePageChanged" />
        </div>
    </div>
}

@code {
    private const int PageSize = 12;

    private List<string> _categories = [];
    private ProductFilter _filter = new(null, null, null, false);
    private string _sortBy = "price_asc";
    private int _currentPage = 1;
    private PagedResult<Product>? _result;
    private bool _loading = true;
    private string? _error;

    private int _totalPages => _result is null ? 0 : (int)Math.Ceiling((double)_result.TotalCount / PageSize);

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    protected override async Task OnInitializedAsync()
    {
        await LoadDataAsync();
    }

    private async Task LoadDataAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var productsTask = ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);

            await Task.WhenAll(categoriesTask, productsTask);

            _categories = await categoriesTask;
            _result = await productsTask;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task SearchAsync()
    {
        _loading = true;
        _error = null;

        try
        {
            _result = await ProductService.SearchAsync(_filter, _sortBy, _currentPage, PageSize);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private async Task HandleFilterApplied(ProductFilter filter)
    {
        _filter = filter;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleFilterCleared()
    {
        _filter = new ProductFilter(null, null, null, false);
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string sortBy)
    {
        _sortBy = sortBy;
        _currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        _currentPage = page;
        await SearchAsync();
    }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart functionality
        return Task.CompletedTask;
    }

    private async Task RetryLoad()
    {
        await LoadDataAsync();
    }
}

.catalog-layout {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    flex-shrink: 0;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.loading-state {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 4rem;
    color: #6c757d;
    font-size: 1.1rem;
}

.error-banner {
    background: #f8d7da;
    border: 1px solid #f5c2c7;
    color: #842029;
    padding: 1rem 1.5rem;
    border-radius: 8px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.error-banner p {
    margin: 0;
}

.error-banner button {
    padding: 0.4rem 1rem;
    background: #842029;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

