toolArgs.file_text:
.catalog-layout {
    display: flex;
    gap: 2rem;
    align-items: flex-start;
}

.catalog-sidebar {
    width: 25%;
    min-width: 220px;
    flex-shrink: 0;
}

.catalog-main {
    flex: 1;
    min-width: 0;
}

.loading-state {
    display: flex;
    justify-content: center;
    align-items: center;
    padding: 4rem;
    color: #6c757d;
    font-size: 1.1rem;
}

.error-banner {
    background: #f8d7da;
    border: 1px solid #f5c2c7;
    color: #842029;
    padding: 1rem 1.5rem;
    border-radius: 8px;
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.error-banner p {
    margin: 0;
}

.error-banner button {
    padding: 0.4rem 1rem;
    background: #842029;
    color: #fff;
    border: none;
    border-radius: 4px;
    cursor: pointer;
}

